package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP11RegistroNombreMinimoPlaywrightTest extends BaseTestPlaywright {    @Test    void registroConNombreMinimoTresCaracteres() {        page.navigate("https://ernest.xo.je/index.php?route=auth/register");        String usuarioUnico =                "ana" + System.currentTimeMillis();        page.locator("input[name='name']")                .fill("Ana");        page.locator("input[name='username']")                .fill(usuarioUnico);        page.locator("input[name='password']")                .fill("pass01");        page.locator("button[type='submit']")                .click();        page.waitForTimeout(2000);        String contenido = page.content().toLowerCase();        String url = page.url().toLowerCase();        assertTrue(                contenido.contains("login")                        || contenido.contains("iniciar")                        || contenido.contains("registr")                        || url.contains("login"),                "El sistema no aceptó el registro con nombre mínimo de 3 caracteres."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP11-registro-nombre-minimo.png"))                        .setFullPage(true)        );    }}